#include<stdio.h>
#include<string.h>

int main()
{
    char st[105];
    int n,nono=0;
    scanf("%d",&n);
    scanf("%s",st);
    printf("%c",st[0]);
    for(int j=1;j<n;j++)
    {
        if((st[j]=='a' || st[j]=='e' || st[j]=='i' || st[j]=='o' || st[j]=='u' || st[j]=='y') && (st[j-1]=='a' || st[j-1]=='e' || st[j-1]=='i' || st[j-1]=='o' || st[j-1]=='u' || st[j-1]=='y'))
            nono++;
        else
            printf("%c",st[j]);
    }
    printf("\n");
return 0;
}

