use std::io::*;

fn is_vowel(c: char) -> bool {
    match c {
        'a' | 'e' | 'i' | 'o'| 'u' | 'y' => {
            true
        },
        _ => false
    }
}

fn main () {
    let mut buf = String::new();
    stdin().read_line(&mut buf).unwrap();
    buf.clear();
    stdin().read_line(&mut buf).unwrap();
    let s = buf.trim();
    let mut res = Vec::<char>::new();
    let mut second_vowel = false;
    for c in s.chars() {
        if is_vowel(c) {
            if !second_vowel {
                second_vowel = true;
                res.push(c);
            }
        } else {
            res.push(c);
            second_vowel = false;
        }
    }
    println!("{}", res.into_iter().collect::<String>());
}
